"""Unit tests for Reimaginer registry wiring."""

from __future__ import annotations

from agents.project_team.discovery_agents import (
    REIMAGINER_REGISTRY_SCHEMAS,
    ReimaginerInput,
)


def test_reimaginer_input_accepts_discovery_only() -> None:
    payload = ReimaginerInput.model_validate(
        {
            "discovery": {
                "repo": "o/r",
                "discovery_ref": "main",
                "discovery_path": ".rebaseai/discovery/artifacts/",
            }
        }
    )
    assert payload.discovery is not None
    assert payload.discovery.repo == "o/r"


def test_reimaginer_input_accepts_flat_discovery_for_backward_compat() -> None:
    payload = ReimaginerInput.model_validate(
        {
            "repo": "o/r",
            "discovery_ref": "main",
            "discovery_path": ".rebaseai/discovery/artifacts/",
        }
    )
    assert payload.discovery is not None
    assert payload.discovery.discovery_ref == "main"


def test_reimaginer_input_accepts_previous_proposal_text_and_guidance() -> None:
    payload = ReimaginerInput.model_validate(
        {
            "previous_proposal": {"type": "text", "text": "# Proposal A"},
            "guidance": "Lean harder into agent autonomy.",
        }
    )
    assert payload.guidance == "Lean harder into agent autonomy."
    assert payload.previous_proposal is not None
    assert payload.previous_proposal.type == "text"


def test_reimaginer_input_accepts_previous_proposal_location() -> None:
    payload = ReimaginerInput.model_validate(
        {
            "previous_proposal": {
                "type": "location",
                "repo": "o/r",
                "ref": "reimaginer/x1",
                "path": "reimaginer/x1/proposal-1.md",
            }
        }
    )
    assert payload.previous_proposal is not None
    assert payload.previous_proposal.type == "location"


def test_reimaginer_registry_schemas_include_input() -> None:
    assert ReimaginerInput in REIMAGINER_REGISTRY_SCHEMAS

