def _nested_models_from_annotation(annotation: Any) -> list[type[BaseModel]]:
    if isinstance(annotation, type) and issubclass(annotation, BaseModel):
        return [annotation]
    origin = get_origin(annotation)
    if origin in (Union, UnionType):
        nested: list[type[BaseModel]] = []
        for arg in get_args(annotation):
            if arg is type(None):
                continue
            nested.extend(_nested_models_from_annotation(arg))
        return nested
    return []


def _append_field_lines(
    lines: list[str],
    *,
    model: type[BaseModel],
    indent: int,
) -> None:
    pad = "  " * indent
    for name, field_info in model.model_fields.items():
        required = "required" if field_info.is_required() else "optional"
        description = field_info.description or ""
        lines.append(f"{pad}- {name} ({required}): {description}")
        for nested in _nested_models_from_annotation(field_info.annotation):
            _append_field_lines(lines, model=nested, indent=indent + 1)


def format_input_contract(model: type[BaseModel]) -> str:
    """Markdown summary of input fields for agent instructions and routing."""
